using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string? dbName = null)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
            Assert.IsTrue(notification.Message.Contains("created"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            // Act
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 42"));
            Assert.IsTrue(notification.Message.Contains("updated"));
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE operation")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE operation")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE operation")]
        public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
        {
            // Act
            _sut.SendNotification("Department", "5", "Engineering", operation, "System");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(operation.ToString(), notification.Operation);
            Assert.IsTrue(notification.Message.Contains(expectedVerb));
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNotNull(second);
            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("2", second.EntityId);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            // Assert
            var after = DateTime.Now;
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - should not throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PersonModelTests
    {
        [TestMethod]
        [DataRow("Smith", "John", "Smith, John", DisplayName = "Standard name")]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
        [DataRow("A", "B", "A, B", DisplayName = "Single character names")]
        public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            // Act
            var result = student.FullName;

            // Assert
            Assert.AreEqual(expected, result);
        }

        [TestMethod]
        public void Student_InheritsFromPerson()
        {
            // Arrange & Act
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Today
            };

            // Assert
            Assert.IsInstanceOfType(student, typeof(Person));
            Assert.AreEqual(1, student.ID);
        }

        [TestMethod]
        public void Instructor_InheritsFromPerson()
        {
            // Arrange & Act
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };

            // Assert
            Assert.IsInstanceOfType(instructor, typeof(Person));
            Assert.AreEqual("Prof, Test", instructor.FullName);
        }

        [TestMethod]
        public void Student_Enrollments_InitializesAsNull()
        {
            // Arrange & Act
            var student = new Student();

            // Assert
            Assert.IsNull(student.Enrollments);
        }

        [TestMethod]
        public void Instructor_CourseAssignments_InitializesAsNull()
        {
            // Arrange & Act
            var instructor = new Instructor();

            // Assert
            Assert.IsNull(instructor.CourseAssignments);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Create_ReturnsCorrectPageItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(10, result[9]);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(20, result[9]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(21, result[0]);
            Assert.AreEqual(25, result[4]);
        }

        [TestMethod]
        [DataRow(25, 10, 3, DisplayName = "25 items, page size 10 = 3 pages")]
        [DataRow(20, 10, 2, DisplayName = "20 items, page size 10 = 2 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
        public void Create_CalculatesTotalPagesCorrectly(int itemCount, int pageSize, int expectedPages)
        {
            // Arrange
            var source = Enumerable.Range(1, itemCount).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedPages, result.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.IsTrue(result.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void PageIndex_ReturnsCorrectValue()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
        }

        [TestMethod]
        public void Constructor_SetsPropertiesCorrectly()
        {
            // Arrange & Act
            var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 2, 5);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(2, list.TotalPages);
            Assert.AreEqual(2, list.Count);
            Assert.IsTrue(list.HasPreviousPage);
            Assert.IsFalse(list.HasNextPage);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context = null!;
        private StudentsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) },
                new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(5, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

