        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var dept = new Department { Name = "TestDept", Budget = 1000, StartDate = DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course { CourseID = 600, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);

            var student = new Student
            {
                LastName = "Enrolled",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today
            };
            context.Students.Add(student);
            context.SaveChanges();

            var enrollment = new Enrollment
            {
                CourseID = course.CourseID,
                StudentID = student.ID,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            // Assert
            var retrieved = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First(e => e.StudentID == student.ID);
