            context.Students.Add(new Student { LastName = "S", FirstMidName = "One", EnrollmentDate = DateTime.Today });
            context.Instructors.Add(new Instructor { LastName = "I", FirstMidName = "One", HireDate = DateTime.Today });
            context.SaveChanges();

            // Act & Assert
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual(1, context.Instructors.Count());
            Assert.AreEqual(2, context.People.Count());
        }
    }
