using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
            Assert.IsTrue(notification.Message.Contains("created"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            // Act
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 42"));
            Assert.IsTrue(notification.Message.Contains("updated"));
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE operation")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE operation")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE operation")]
        public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedVerb)
        {
            // Act
            _sut.SendNotification("Department", "5", "Engineering", operation, "System");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(operation.ToString(), notification.Operation);
            Assert.IsTrue(notification.Message.Contains(expectedVerb));
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNotNull(second);
            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("2", second.EntityId);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            // Assert
            var after = DateTime.Now;
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op for in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - should not throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

