{"file_text": "using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Create_ReturnsCorrectPageItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(10, result[9]);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(20, result[9]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(21, result[0]);
            Assert.AreEqual(25, result[4]);
        }

        [TestMethod]
        [DataRow(25, 10, 3, DisplayName = "25 items, page size 10 = 3 pages")]
        [DataRow(20, 10, 2, DisplayName = "20 items, page size 10 = 2 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
        public void Create_CalculatesTotalPagesCorrectly(int itemCount, int pageSize, int expectedPages)
        {
            // Arrange
            var source = Enumerable.Range(1, itemCount).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedPages, result.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.IsTrue(result.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void PageIndex_ReturnsCorrectValue()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.AreEqual(2, result.PageIndex);
        }

        [TestMethod]
        public void Constructor_SetsPropertiesCorrectly()
        {
            // Arrange & Act
            var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 2, 5);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(2, list.TotalPages);
            Assert.AreEqual(2, list.Count);
            Assert.IsTrue(list.HasPreviousPage);
            Assert.IsFalse(list.HasNextPage);
        }
    }
}
