        {
            // Arrange & Act
            using var context = TestDbContextFactory.Create();

            // Assert
            Assert.IsNotNull(context);
            Assert.IsNotNull(context.Students);
            Assert.IsNotNull(context.Courses);
            Assert.IsNotNull(context.Departments);
            Assert.IsNotNull(context.Instructors);
            Assert.IsNotNull(context.Enrollments);
            Assert.IsNotNull(context.CourseAssignments);
            Assert.IsNotNull(context.OfficeAssignments);
            Assert.IsNotNull(context.Notifications);
        }

        [TestMethod]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            context.Students.Add(student);
            context.SaveChanges();

            // Assert
            var retrieved = context.Students.First(s => s.LastName == "Smith");
            Assert.IsNotNull(retrieved);
            Assert.AreEqual("John", retrieved.FirstMidName);
            Assert.AreEqual(new DateTime(2023, 9, 1), retrieved.EnrollmentDate);
        }

        [TestMethod]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var instructor = new Instructor { LastName = "Test", FirstMidName = "Prof", HireDate = DateTime.Today };
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Today };
            context.Departments.Add(dept);
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var course = new Course { CourseID = 500, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);
            context.SaveChanges();

            // Act
            var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
            context.CourseAssignments.Add(assignment);
            context.SaveChanges();

            // Assert
            var retrieved = context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.IsNotNull(retrieved);
        }

        [TestMethod]
        public void SchoolContext_InstructorOfficeAssignment_OneToOne()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Today,
                OfficeAssignment = new OfficeAssignment { Location = "Building A, Room 101" }
            };

            // Act
            context.Instructors.Add(instructor);
            context.SaveChanges();

            // Assert
            var retrieved = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.LastName == "Office");
            Assert.IsNotNull(retrieved.OfficeAssignment);
            Assert.AreEqual("Building A, Room 101", retrieved.OfficeAssignment.Location);
        }

        [TestMethod]
        public void SchoolContext_StudentEnrollments_Relationship()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var dept = new Department { Name = "TestDept", Budget = 1000, StartDate = DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course { CourseID = 600, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);

            var student = new Student
            {
                LastName = "Enrolled",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today
            };
            context.Students.Add(student);
            context.SaveChanges();

            var enrollment = new Enrollment
            {
                CourseID = course.CourseID,
                StudentID = student.ID,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            // Assert
            var retrieved = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First(e => e.StudentID == student.ID);
            Assert.IsNotNull(retrieved.Student);
            Assert.IsNotNull(retrieved.Course);
            Assert.AreEqual(Grade.A, retrieved.Grade);
        }

        [TestMethod]
        public void SchoolContext_TPH_DiscriminatesStudentsAndInstructors()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            context.Students.Add(new Student { LastName = "S", FirstMidName = "One", EnrollmentDate = DateTime.Today });
            context.Instructors.Add(new Instructor { LastName = "I", FirstMidName = "One", HireDate = DateTime.Today });
            context.SaveChanges();

            // Act & Assert
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual(1, context.Instructors.Count());
            Assert.AreEqual(2, context.People.Count());
        }
    }
}
