using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PersonModelTests
    {
        [TestMethod]
        [DataRow("Smith", "John", "Smith, John", DisplayName = "Standard name")]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
        [DataRow("A", "B", "A, B", DisplayName = "Single character names")]
        public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            // Arrange
            var student = new Student { LastName = lastName, FirstMidName = firstName };

            // Act
            var result = student.FullName;

            // Assert
            Assert.AreEqual(expected, result);
        }

        [TestMethod]
        public void Student_InheritsFromPerson()
        {
            // Arrange & Act
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Today
            };

            // Assert
            Assert.IsInstanceOfType(student, typeof(Person));
            Assert.AreEqual(1, student.ID);
        }

        [TestMethod]
        public void Instructor_InheritsFromPerson()
        {
            // Arrange & Act
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };

            // Assert
            Assert.IsInstanceOfType(instructor, typeof(Person));
            Assert.AreEqual("Prof, Test", instructor.FullName);
        }

        [TestMethod]
        public void Student_Enrollments_InitializesAsNull()
        {
            // Arrange & Act
            var student = new Student();

            // Assert
            Assert.IsNull(student.Enrollments);
        }

        [TestMethod]
        public void Instructor_CourseAssignments_InitializesAsNull()
        {
            // Arrange & Act
            var instructor = new Instructor();

            // Assert
            Assert.IsNull(instructor.CourseAssignments);
        }
    }
}

