using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context = null!;
        private StudentsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2022, 9, 1) },
                new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(5, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Li", model[0].LastName);
            Assert.AreEqual("Barzdukas", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2020, 9, 1), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            // Act
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2022, 9, 1), model[0].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudentsByLastName()
        {
            // Act
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            // Act
            var result = _controller.Index(null, null, "Yan", null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Li", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchStringProvided_ResetsPageTo1()
        {
            // Act
            var result = _controller.Index(null, null, "A", 3) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            // Act
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            // Assert
            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_SetsViewBagProperties()
        {
            // Act
            var result = _controller.Index("Date", null, "test", null) as ViewResult;

            // Assert
            Assert.AreEqual("Date", _controller.ViewBag.CurrentSort);
            Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
            Assert.AreEqual("", _controller.ViewBag.NameSortParm);
            Assert.AreEqual("test", _controller.ViewBag.CurrentFilter);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = _context.Students.First();

            // Act
            var result = _controller.Details(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Create_Get_ReturnsViewWithStudentAndTodayDate()
        {
            // Act
            var result = _controller.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(6, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_MinValueEnrollmentDate_ReturnsViewWithError()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_DateBelow1753_ReturnsViewWithError()
        {
            // Arrange
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = _context.Students.First();

            // Act
            var result = _controller.Edit(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Edit(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Edit(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = _context.Students.First();
            // Detach to avoid tracking conflicts
            _context.Entry(student).State = EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = student.ID,
                LastName = "UpdatedName",
                FirstMidName = student.FirstMidName,
                EnrollmentDate = student.EnrollmentDate
            };

            // Act
            var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_MinValueEnrollmentDate_ReturnsViewWithError()
        {
            // Arrange
            var student = _context.Students.First();
            _context.Entry(student).State = EntityState.Detached;

            var badStudent = new Student
            {
                ID = student.ID,
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Edit(badStudent) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_controller.ModelState.IsValid);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = _context.Students.First();

            // Act
            var result = _controller.Delete(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _controller.Delete(9999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            // Arrange
            var student = _context.Students.First();
            var initialCount = _context.Students.Count();

            // Act
            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(initialCount - 1, _context.Students.Count());
        }
    }
}

