        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SeedData(SchoolContext context)
        {
            var instructor = new Instructor
            {
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2015, 3, 1)
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.Departments.AddRange(
                new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2010, 9, 1), InstructorID = instructor.ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2012, 9, 1) },
                new Department { Name = "English", Budget = 75000, StartDate = new DateTime(2011, 9, 1) }
            );
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_ReturnsViewWithAllDepartments()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            // Arrange
            var dept = _context.Departments.First();

            // Act
            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.IsNotNull(model);
            Assert.AreEqual(dept.Name, model.Name);
        }

