using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context = null!;
        private InstructorsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedData(_context);
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SeedData(SchoolContext context)
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            context.Departments.Add(dept);

            var course1 = new Course { CourseID = 101, Title = "Calculus", Credits = 4, DepartmentID = 1 };
            var course2 = new Course { CourseID = 102, Title = "Physics", Credits = 3, DepartmentID = 1 };
            context.Courses.AddRange(course1, course2);

            var instructor1 = new Instructor
            {
                LastName = "Kapoor",
                FirstMidName = "Candace",
                HireDate = new DateTime(2015, 3, 1),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" },
                CourseAssignments = new List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                LastName = "Zheng",
                FirstMidName = "Roger",
                HireDate = new DateTime(2018, 7, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor1.ID, CourseID = 101 });
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            // Act
            var result = _controller.Index(null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Arrange
            var instructor = _context.Instructors.First(i => i.LastName == "Kapoor");

            // Act
            var result = _controller.Index(instructor.ID, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
            Assert.IsTrue(model.Courses.Any());
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Arrange
            var instructor = _context.Instructors.First();

            // Act
            var result = _controller.Details(instructor.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual(instructor.LastName, model.LastName);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _controller.Details(null) as StatusCodeResult;

