using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context = null!;
        private HomeController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedStudents(_context);
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "Student1", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "B", FirstMidName = "Student2", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { LastName = "C", FirstMidName = "Student3", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            context.SaveChanges();
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentStats()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count); // Two distinct enrollment dates
        }

        [TestMethod]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            var model = result!.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            var group2020 = model.First(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
            Assert.AreEqual(2, group2020.StudentCount);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            // Act
            var result = _controller.Contact() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsView()
        {
            // Act
            var result = _controller.Error() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithPermissionMessage()
        {
            // Act
            var result = _controller.Unauthorized() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
