using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context = null!;
        private NotificationsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            // Drain any leftover notifications from the static queue
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);

            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            Assert.AreEqual(0, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsCorrectCount()
        {
            // Arrange - enqueue some notifications via the service
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
            service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");
            service.Dispose();

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value!;
            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            Assert.AreEqual(2, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            // Arrange - enqueue 15 notifications
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE);
            }
            service.Dispose();

            // Act
            var result = _controller.GetNotifications() as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value!;
            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(countProp);
            Assert.AreEqual(10, countProp.GetValue(value));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1) as JsonResult;

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value!;
            var successProp = value.GetType().GetProperty("success");
            Assert.IsNotNull(successProp);
            Assert.AreEqual(true, successProp.GetValue(value));
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }
    }
}

